class Solution {
    private static final int MOD = (int) 1e9 + 7;
    public int countKReducibleNumbers(String s, int k) {
        int n = Integer.parseInt(s, 2);
        int[][] dp = new int[k + 1][n + 1];
        dp[0][1] = 1;
        for (int i = 1; i <= k; i++) {
            for (int j = 1; j <= n; j++) {
                int count = Integer.bitCount(j);
                if (count <= n) {
                    dp[i][count] = (dp[i][count] + dp[i - 1][j]) % MOD;
                }
            }
        }
        int res = 0;
        for (int i = 1; i <= k; i++) {
            res = (res + dp[i][1]) % MOD;
        }
        return res;
    }
}
